&lt;p&gt;&lt;strong&gt;&lt;u&gt;Pancreas:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Located towards the back of the&lt;strong&gt; abdomen &lt;/strong&gt;behind the&lt;strong&gt; stomach&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;It is also called &lt;strong&gt;islands of Langerhans&lt;/strong&gt; which consist of four types of cells: &lt;strong&gt;alpha cells, beta cells, delta cells, and F cells&lt;/strong&gt;,&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;u&gt;&lt;strong&gt;Type of cell&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;u&gt;&lt;strong&gt;Hormone release&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;u&gt;&lt;strong&gt;function of hormone&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Beta-cell&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Insulin&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Regulates blood glucose/sugar levels.&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Alpha cells&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Glucagon&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Change of liver glycogen to blood glucose(glycogenolysis).&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;Forms glucose from amino acids and fats (glyconeogenesis).&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Delta cell&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Somatostatin&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Decreases the rate of nutrient absorption into the bloodstream from the gastrointestinal tract.&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;An inhibitor of insulin and glycogen.&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;F cells&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Pancreatic Polypeptide&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;Inhibits the release of pancreatic juice.&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;&lt;strong&gt;अग्न्याशय:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;उदर&lt;/strong&gt; के पीछे पेट के पीछे की ओर स्थित होते है।&lt;/li&gt;
	&lt;li&gt;इसे &lt;strong&gt;आइलैंड ऑफ़ लैंगरहंस &lt;/strong&gt;भी कहा जाता है, जिसमें चार प्रकार की कोशिकाएँ होती हैं: &lt;strong&gt;अल्फा कोशिकाएँ, बीटा कोशिकाएँ, डेल्टा कोशिकाएँ और &lt;span style=&quot;font-weight: 700;&quot;&gt;F &lt;/span&gt; कोशिकाएँ,&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;  (255, 255, 255); width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;u&gt;&lt;strong&gt;कोशिकाओं का प्रकार&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;u&gt;&lt;strong&gt;हार्मोन उत्सर्जन &lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;u&gt;&lt;strong&gt;हार्मोन का कार्य&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;बीटा &lt;span style=&quot;text-align: center;&quot;&gt;कोशिकाएं&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;इंसुलिन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;रक्त शर्करा / शर्करा के स्तर को नियंत्रित करता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;अल्फा कोशिकाएं&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;ग्लूकागन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p&gt;यकृत ग्लाइकोजन को रक्त शर्करा (ग्लाइकोजेनोलिसिस) में बदलना।&lt;/p&gt;

			&lt;p&gt;अमीनो एसिड और वसा (ग्लाइकोनोजेनेसिस) से ग्लूकोज का निर्माण करता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;डेल्टा &lt;span style=&quot;text-align: center;&quot;&gt;कोशिकाएं&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;सोमेटोस्टैटिन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p&gt;जठरांत्र संबंधी मार्ग से रक्तप्रवाह में पोषक तत्वों के अवशोषण की दर को कम करता है।&lt;/p&gt;

			&lt;p&gt;इंसुलिन और ग्लाइकोजन का अवरोध करनेवाला।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;F &lt;span style=&quot;text-align: center;&quot;&gt;कोशिकाएं&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;अग्नाशयी पॉलीपेप्टाइड&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 201px;&quot;&gt;
			&lt;p&gt;अग्नाशयी रस की रिहाई को रोकता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Concept -&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Mitochondria:&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Mitochondria are membrane-bound organelles present in all eukaryotic cells&amp;#39; cytoplasm.&lt;/li&gt;
	&lt;li&gt;Typically it is sausage-shaped or cylindrical having a diameter of 0.2-1.0&amp;micro;m (average 0.5&amp;micro;m) and length 1.0-4.1&amp;micro;m.&lt;/li&gt;
	&lt;li&gt;Each mitochondrion is a double membrane-bound structure with the outer membrane and the inner membrane dividing its lumen distinctly into two aqueous compartments, i.e.&amp;nbsp;the outer compartment and the inner compartment.&lt;/li&gt;
	&lt;li&gt;The inner compartment is filled with a dense homogeneous substance called the matrix.&lt;/li&gt;
	&lt;li&gt;The outer membrane forms the continuous limiting boundary of the organelle. The inner membrane forms a number of infoldings called the cristae&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Mitochondria for aerobic respiration:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Mitochondria are the sites of &lt;strong&gt;aerobic &lt;/strong&gt;respiration.&lt;/li&gt;
	&lt;li&gt;They produce &lt;strong&gt;cellular energy in the form of ATP&lt;/strong&gt;, hence they are called &amp;lsquo;&lt;strong&gt;power houses&lt;/strong&gt;&amp;rsquo; of the cell.&lt;/li&gt;
	&lt;li&gt;A series of chemical reactions occur in the cytoplasm as breakdown products from food digestion find their way into the cell.&lt;/li&gt;
	&lt;li&gt;This allows some of the energy stored up in these items to be released and integrated into ATP, the cell&amp;#39;s universal energy source (adenosine triphosphate).&lt;/li&gt;
	&lt;li&gt;The remaining molecular fragments from this phase then reach the mitochondria, where they are converted to carbon dioxide and water through a complex sequence of steps.&lt;/li&gt;
	&lt;li&gt;The energy that has been trapped in these fragments is converted into more &lt;strong&gt;ATP&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The cell can then use the&lt;strong&gt; ATP molecules generated&lt;/strong&gt; in this way to provide the energy it requires to work.&lt;/li&gt;
	&lt;li&gt;To function, ATP is made up of ADP + P + energy.&lt;/li&gt;
	&lt;li&gt;The overall&amp;nbsp;chemical reaction&amp;nbsp;that occurs when&amp;nbsp;glucose&amp;nbsp;is broken down is:&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;box-sizing: inherit; margin-bottom: 1.5rem;&quot;&gt;&lt;strong&gt;C&lt;span style=&quot;box-sizing: inherit; line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;6&lt;/span&gt;H&lt;span style=&quot;box-sizing: inherit; line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;12&lt;/span&gt;O&lt;sub&gt;6&lt;/sub&gt; +&lt;span style=&quot;box-sizing: inherit; line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;&amp;nbsp;&amp;nbsp;&lt;/span&gt;6O&lt;sub&gt;2 &lt;/sub&gt;------------&amp;gt;&amp;nbsp; 6CO&lt;sub&gt;2&lt;/sub&gt; +&amp;nbsp;6H&lt;sub&gt;2&lt;/sub&gt;O +&amp;nbsp; ATP (energy)&amp;nbsp;&lt;span style=&quot;box-sizing: inherit; line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Explanation -&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The mitochondria are the site for &lt;strong&gt;aerobic respiration releasing energy &lt;/strong&gt;in the form of &lt;strong&gt;ATP&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;As mitochondria produce &lt;strong&gt;ATP (energy) &lt;/strong&gt;which is then utilized by the entire cell to function, it is thus called the powerhouse of the cell.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Hence the correct answer for this question is &lt;strong&gt;&lt;u&gt;option 4&lt;/u&gt;.&amp;nbsp;&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;u&gt;&lt;strong&gt;अवधारणा&lt;/strong&gt;&lt;/u&gt; -&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;सूत्रकणिका:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सूत्रकणिका झिल्ली-बद्ध &lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;कोशिकांग&lt;/span&gt;&lt;/span&gt; हैं जो सभी &lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;सुकेंद्रीकी कोशिका&lt;/span&gt;&lt;/span&gt;ओं के कोशिकाद्रव्य में मौजूद होते हैं।&lt;/li&gt;
	&lt;li&gt;आमतौर पर यह सॉसेज के आकार का या बेलनाकार होते हैं जिनका व्यास 0.2-1.0 माइक्रोमीटर (औसत 0.5 माइक्रोमीटर) और लंबाई 1.0-4.1 माइक्रोमीटर होती है।&lt;/li&gt;
	&lt;li&gt;प्रत्येक सूत्रकणिका बाहरी झिल्ली के साथ एक दोहरी झिल्ली-बद्ध संरचना होती है और आंतरिक झिल्ली अपने &lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;अवकाशिका (&lt;/span&gt;&lt;/span&gt;लुमेन) को दो &lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;नेत्रोद कक्ष&lt;/span&gt;&lt;/span&gt;, यानी बाहरी कक्ष और आंतरिक कक्ष में अलग-अलग विभाजित करती है।&lt;/li&gt;
	&lt;li&gt;आंतरिक कक्ष एक सघन&amp;nbsp;समांग पदार्थ से भरा होता है जिसे मैट्रिक्स कहा जाता है।&lt;/li&gt;
	&lt;li&gt;बाहरी झिल्ली कोशिकांग की &lt;span style=&quot;&quot;&gt;सतत&lt;/span&gt; सीमित सीमा बनाती है। आंतरिक झिल्ली क्रिस्टी (cristae) कहे जाने वाले कई प्रकार के&amp;nbsp;&lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;अंतर्वलि&lt;/span&gt;&lt;/span&gt; बनाती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;ऑक्सीय श्वसन&lt;/span&gt;&lt;/span&gt; के लिए सूत्रकणिका:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सूत्रकणिका &lt;strong&gt;ऑक्सीय&lt;/strong&gt; श्वसन के स्थल हैं।&lt;/li&gt;
	&lt;li&gt;वे &lt;strong&gt;एटीपी के रूप में &lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;कोशिकीय&lt;/span&gt;&lt;/span&gt; ऊर्जा &lt;/strong&gt;का उत्पादन करते हैं, इसलिए उन्हें कोशिका का &lt;strong&gt;&amp;#39;पावर हाउस&amp;#39;&lt;/strong&gt; कहा जाता है।&lt;/li&gt;
	&lt;li&gt;कोशिकाद्रव्य में रासायनिक अभिक्रियाओं की एक श्रृंखला होती है जब भोजन के पाचन से टूटने वाले उत्पाद कोशिका में अपना रास्ता तलाशते हैं।&lt;/li&gt;
	&lt;li&gt;यह इन वस्तुओं में संग्रहीत कुछ ऊर्जा को एटीपी&lt;span style=&quot;&quot;&gt;, कोशिका का सार्वभौमिक ऊर्जा स्रोत (एडेनोसिन ट्राइफॉस्फेट),&lt;/span&gt; में जारी करने और एकीकृत करने की अनुमति देते हैं।&lt;/li&gt;
	&lt;li&gt;इस चरण से शेष आणविक टुकड़े तब सूत्रकणिका तक पहुंचते हैं, जहां वे चरणों के एक जटिल अनुक्रम के माध्यम से कार्बन डाइऑक्साइड और पानी में परिवर्तित हो जाते हैं।&lt;/li&gt;
	&lt;li&gt;इन टुकड़ों में जो ऊर्जा फंसी हुई है, वह और&amp;nbsp;&lt;strong&gt;एटीपी&lt;/strong&gt; में बदल जाती है।&lt;/li&gt;
	&lt;li&gt;कोशिका तब इस तरह से &lt;strong&gt;उत्पन्न एटीपी अणुओं&lt;/strong&gt; का उपयोग कर सकती है ताकि वह काम करने के लिए आवश्यक ऊर्जा प्रदान कर सके।&lt;/li&gt;
	&lt;li&gt;कार्य करने के लिए, एटीपी, ADP + P + ऊर्जा से बना है।&lt;/li&gt;
	&lt;li&gt;ग्लूकोज के टूटने पर होने वाली समग्र रासायनिक अभिक्रिया है:&lt;/li&gt;
	&lt;li&gt;&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;C&lt;span style=&quot;box-sizing: inherit; line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;6&lt;/span&gt;H&lt;span style=&quot;box-sizing: inherit; line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;12&lt;/span&gt;O&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;6&lt;/span&gt;&amp;nbsp;+&lt;span style=&quot;box-sizing: inherit; line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;&amp;nbsp;&amp;nbsp;&lt;/span&gt;6O&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&amp;nbsp;&lt;/span&gt;------------&amp;gt;&amp;nbsp; 6CO&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;+&amp;nbsp;6H&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;O +&amp;nbsp; ATP&lt;/span&gt; + &lt;strong&gt;एटीपी (ऊर्जा)&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;स्पष्टीकरण&lt;/strong&gt;&lt;/u&gt; -&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सूत्रकणिका एटीपी के रूप में &lt;strong&gt;ऊर्जा जारी करने वाले ऑक्सीय&amp;nbsp;श्वसन&lt;/strong&gt;&amp;nbsp;के लिए स्थल है।&lt;/li&gt;
	&lt;li&gt;जैसा कि सूत्रकणिका &lt;strong&gt;एटीपी (ऊर्जा) &lt;/strong&gt;का उत्पादन करते हैं जो तब पूरे कोशिका द्वारा कार्य करने के लिए उपयोग &amp;nbsp;की जाती है, इसे इस प्रकार कोशिका का शक्ति गृह कहा जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः, इस प्रश्न का सही विकल्प &lt;b&gt;&lt;u&gt;विकल्प 4&lt;/u&gt;&lt;/b&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;The correct answer is option 3) i.e. freefall of the spacecraft&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;CONCEPT&lt;/u&gt;&lt;/span&gt;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Weight:&lt;/span&gt; The &lt;span style=&quot;font-weight: 700;&quot;&gt;weight &lt;/span&gt;of an object is the &lt;span style=&quot;font-weight: 700;&quot;&gt;force &lt;/span&gt;with which it is pulled by gravity.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;It is given by:&lt;/p&gt;

&lt;p&gt;W = mg&lt;/p&gt;

&lt;p&gt;Where m is the mass of the body and g is the acceleration due to gravity.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Weightlessness: &lt;/span&gt;Weightlessness is a sensation experienced by a body in the absence of any forces of gravity acting on it.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;EXPLANATION&lt;/u&gt;:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Every part of the spacecraft orbiting the earth has an acceleration towards the centre of the earth which is exactly the value of earth&amp;rsquo;s acceleration due to gravity at that position.&lt;/li&gt;
	&lt;li&gt;Thus in the spacecraft, everything inside it is in a state of &lt;strong&gt;free fall&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;When an object is in free fall, it is &lt;strong&gt;weightless &lt;/strong&gt;as there is &lt;strong&gt;no upward force&lt;/strong&gt; to counteract the gravitational force.&lt;/li&gt;
	&lt;li&gt;Hence, an &lt;strong&gt;object under freefall experiences weightlessness.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Therefore, the &lt;strong&gt;weightlessness experienced by objects in a spacecraft orbiting&lt;/strong&gt; the earth is due to the&lt;strong&gt; freefall of the spacecraft.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर विकल्प 3 है) यानी अंतरिक्ष यान का मुक्त होना&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;अवधारणा&lt;/u&gt;&lt;/span&gt; :&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;वजन&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;:&lt;/span&gt; एक वस्तु का &lt;span style=&quot;font-weight: 700;&quot;&gt;वजन&lt;/span&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;बल&lt;/span&gt; है जिसके साथ यह गुरुत्वाकर्षण द्वारा खींचा जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;यह निम्न द्वारा दिया गया है&lt;/p&gt;

&lt;p&gt;W = mg&lt;/p&gt;

&lt;p&gt;जहाँ m निकाय का द्रव्यमान है और g गुरुत्वाकर्षण के कारण त्वरण है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;भारहीनता:&lt;/span&gt; भारहीनता एक ऐसी अनुभूति होती है जो निकाय द्वारा किसी बल या गुरुत्वाकर्षण के अभाव में अनुभव की जाती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;शोषण&lt;/u&gt; :&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पृथ्वी की परिक्रमा करने वाले अंतरिक्षयान के प्रत्येक भाग में पृथ्वी के केंद्र की ओर एक त्वरण होता है जो कि उस स्थिति में गुरुत्वाकर्षण के कारण पृथ्वी के त्वरण का मान वास्तव में होता है।&lt;/li&gt;
	&lt;li&gt;इस प्रकार अंतरिक्ष यान में, उसके अंदर सब कुछ &lt;strong&gt;मुक्त होने की&lt;/strong&gt; स्थिति में है।&lt;/li&gt;
	&lt;li&gt;जब कोई वस्तु स्वतंत्र रूप से गिरती है, तो यह &lt;strong&gt;भारहीन&lt;/strong&gt; होती है क्योंकि गुरुत्वाकर्षण बल की प्रतिक्रिया करने के लिए &lt;strong&gt;कोई ऊपर की ओर बल नहीं होता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इसलिए, &lt;strong&gt;मुक्त पतन के तहत एक वस्तु भारहीनता का अनुभव करती है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इसलिए, &lt;strong&gt;अंतरिक्ष यान में पृथ्वी की परिक्रमा करने वाली वस्तुओं द्वारा अनुभव की गई भारहीनता अंतरिक्ष यान&lt;/strong&gt; &lt;strong&gt;के मुक्त&lt;/strong&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;पतन &lt;/span&gt;होने के कारण है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is &lt;u&gt;&lt;strong&gt;Option 4&lt;/strong&gt;&lt;/u&gt; i.e&amp;nbsp;&lt;u&gt;&lt;strong&gt;Hemoglobin&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot;&gt;
	&lt;li role=&quot;presentation&quot;&gt;&lt;strong&gt;Lymph&lt;/strong&gt;:

	&lt;ul&gt;
		&lt;li role=&quot;presentation&quot;&gt;The lymph system is a major part of the body&amp;#39;s immune system.&lt;/li&gt;
		&lt;li role=&quot;presentation&quot;&gt;Lymph nodes make immune cells that help the body fight infection.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Melanin&lt;/strong&gt;: Color to skin, hair and eyes are due to the Melanin pigment.&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;
&lt;ul dir=&quot;ltr&quot;&gt;
	&lt;li role=&quot;presentation&quot;&gt;&lt;u&gt;&lt;strong&gt;Hemoglobin&lt;/strong&gt;&lt;/u&gt;:

	&lt;ul&gt;
		&lt;li role=&quot;presentation&quot;&gt;It is the protein inside red blood cells that carries oxygen in humans.&lt;/li&gt;
		&lt;li role=&quot;presentation&quot;&gt;The red color of blood is due to this hemoglobin.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li role=&quot;presentation&quot;&gt;&lt;span style=&quot;  &quot;&gt;&lt;strong&gt;Mucus&lt;/strong&gt;:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li role=&quot;presentation&quot;&gt;&lt;span style=&quot;  &quot;&gt;It is also known as sputum.&lt;/span&gt;&lt;/li&gt;
		&lt;li role=&quot;presentation&quot;&gt;&lt;span style=&quot;  &quot;&gt;It is a fluid substance produced by many lining tissues in the body.&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;विकल्प 4&lt;/strong&gt;&lt;/u&gt; है अर्थात्&amp;nbsp;&lt;u&gt;&lt;strong&gt;हीमोग्लोबिन&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;लसीका:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li style=&quot;&quot;&gt;लसीका प्रणाली शरीर की प्रतिरक्षा प्रणाली का एक प्रमुख हिस्सा है।&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;लसिका पर्व प्रतिरक्षा कोशिकाओं को बनाते हैं जो शरीर को संक्रमण से लड़ने में मदद करते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;मेलेनिन:&lt;/strong&gt; मेलेनिन वर्णक के कारण त्वचा, बाल और आंखों का&amp;nbsp;रंग होता है।&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;हीमोग्लोबिन:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li style=&quot;&quot;&gt;यह लाल रक्त कोशिकाओं के अंदर प्रोटीन है जो मनुष्यों में ऑक्सीजन पहुंचाता है।&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;रक्त का रंग लाल&amp;nbsp;इस हीमोग्लोबिन के कारण होता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;strong&gt;श्लेष्मा:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li style=&quot;&quot;&gt;इसे थूक के रूप में भी जाना जाता है।&lt;/li&gt;
		&lt;li style=&quot;&quot;&gt;यह शरीर में कई लाइनिंग ऊतकों द्वारा निर्मित एक द्रव पदार्थ है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;CONCEPT&lt;/span&gt;&lt;/u&gt;:&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Resistance&lt;/span&gt;: The property of any conductor that opposes the flow of electric current through it is called resistance.

	&lt;ul&gt;
		&lt;li&gt;It is denoted by R and the SI unit is the ohm (&amp;Omega;).&lt;/li&gt;
		&lt;li style=&quot;text-align: justify;&quot;&gt;Superconductors are said to have zero resistance.&lt;/li&gt;
		&lt;li style=&quot;text-align: justify;&quot;&gt;One can control Voltage and Current by altering the resistance of the circuit.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;resistance (R)&lt;/span&gt;&amp;nbsp;is given by:&lt;/p&gt;

&lt;p&gt;R =&amp;nbsp;&amp;rho;L/A&lt;/p&gt;

&lt;p&gt;where&amp;nbsp;&amp;rho; is resistivity, L is the length and A is the area of the cross-section.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;EXPLANATION&lt;/span&gt;&lt;/u&gt;:&lt;/p&gt;

&lt;ol&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;&lt;span id=&quot;cke_bm_28628S&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;The&amp;nbsp;&lt;strong&gt;resistance of a conductor does not depend on Pressure&lt;/strong&gt;. So option 1 is correct.&lt;/li&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;Conductors show less resistance and Insulators show very high resistance. So &lt;strong&gt;it depends on the material&lt;/strong&gt;.&lt;/li&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;It is &lt;strong&gt;inversely proportional to the&amp;nbsp;cross-sectional area&lt;/strong&gt; of the wire.&lt;span id=&quot;cke_bm_31879C&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;The &lt;strong&gt;r&lt;span id=&quot;cke_bm_28628E&quot; style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;esistance is directly proportional to the length&lt;/strong&gt; of the wire and resistivity of the material used in making the wire.&lt;/li&gt;
&lt;/ol&gt;<br><br>&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;धारणा&lt;/span&gt;&lt;/u&gt;:&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;प्रतिरोध:&amp;nbsp;&lt;/span&gt;किसी भी चालक का गुण जो इसके माध्यम से विद्युत धारा के प्रवाह का विरोध करता है, प्रतिरोध कहलाता है।

	&lt;ul&gt;
		&lt;li&gt;इसे R द्वारा दर्शाया गया है और SI इकाई ओम (&amp;Omega;) है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;text-align: justify;&quot;&gt;अतिचालक के पास शून्य प्रतिरोध है ऐसा कहा जाता है।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;text-align: justify;&quot;&gt;परिपथ के प्रतिरोध को बदलकर वोल्टेज और धारा को नियंत्रित किया जा सकता है।&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;प्रतिरोध&amp;nbsp;&lt;/span&gt;निम्न द्वारा दिया गया है:&lt;/p&gt;

&lt;p&gt;R =&amp;nbsp;&amp;rho;L/A&lt;/p&gt;

&lt;p&gt;जहां &amp;rho; प्रतिरोधकता है, L लंबाई है और A अनुप्रस्थ-काट का क्षेत्र है।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;व्याख्या&lt;/span&gt;&lt;/u&gt;:&lt;/p&gt;

&lt;ol&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;एक सुचालक का प्रतिरोध &lt;strong&gt;दबाव&lt;/strong&gt;&amp;nbsp;पर निर्भर नहीं करता है।&amp;nbsp;तो विकल्प 1 सही है।&lt;/li&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;सुचालक कम प्रतिरोध दिखाते हैं और अवरोधक बहुत अधिक प्रतिरोध दिखाते हैं।&amp;nbsp;तो यह सामग्री पर निर्भर करता है।&lt;/li&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;यह तार के अनुप्रस्थ काट के क्षेत्र के व्युत्क्रमानुपाती होता है।&lt;/li&gt;
	&lt;li style=&quot;text-align: justify;&quot;&gt;प्रतिरोध तार की लंबाई के सीधे आनुपातिक होता है और प्रयुक्त सामग्री की प्रतिरोधकता तार बनाने में उपयोग आती है।&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;egg, sperm&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Concept:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Unicellular &lt;/strong&gt;(composed of single-cell) and &lt;strong&gt;multicellular &lt;/strong&gt;(composed of many cells).&lt;/li&gt;
	&lt;li&gt;The cells vary in their shapes. They may be polygonal, disclike amoeboid, thread-like, cuboid or irregular.&lt;/li&gt;
	&lt;li&gt;The shape cell is always related and vary with the function they perform.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Explanation:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The male and the female gametes i.e the&lt;strong&gt; sperm and the egg or ova respectively are unicellular &lt;/strong&gt;(single-celled).&lt;/li&gt;
	&lt;li&gt;They &lt;strong&gt;both are haploid (n) &lt;/strong&gt;in nature which undergoes fertilization to form the diploid zygote (2n).&lt;/li&gt;
	&lt;li&gt;Sperm is the smallest cell in the human body.&lt;/li&gt;
	&lt;li&gt;Each sperm is a single cell. Sperm is a male gamete that is produced from germ cells.&lt;/li&gt;
	&lt;li&gt;They are produced by &lt;strong&gt;meiosis&lt;/strong&gt;, which results in haploid unicellular cells.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/22/03/F1_Utkarsha_Madhuri_05.03.2022_D1.png&quot; style=&quot;width: 318px; height: 184px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;A &lt;strong&gt;zygote (2n)&lt;/strong&gt; is &lt;strong&gt;formed after fertilisation by the fusion of a female gamete (egg-n) and a male gamete (sperm-n).&lt;/strong&gt; As a result, the &lt;strong&gt;zygote is multicellular.&amp;nbsp;&lt;/strong&gt;&lt;br /&gt;
To form an embryo, &lt;strong&gt;zygote cells differentiate and divide (mitosis).&lt;/strong&gt; The&lt;strong&gt; embryo is a multicellular structure.&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर&lt;u&gt;&lt;strong&gt; &lt;span style=&quot;&quot;&gt;अंडाणु, शुक्राणु&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;अवधारणा:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एककोशिकीय&lt;/strong&gt; (एकल कोशिका से बना) और &lt;strong&gt;बहुकोशिकीय&lt;/strong&gt; (कई कोशिकाओं से बना)।&lt;/li&gt;
	&lt;li&gt;कोशिकाएं अपने आकार में भिन्न होती हैं। वे बहुभुज हो सकती&amp;nbsp;हैं, डिस्क के आकार की&amp;nbsp;अमीबीय हो सकती&amp;nbsp;हैं, धागे की तरह, घनाभ या अनियमित हो सकती&amp;nbsp;हैं।&lt;/li&gt;
	&lt;li&gt;आकार कोशिका&amp;nbsp;&lt;span style=&quot;&quot;&gt;उनके द्वारा किए जाने वाले कार्य के साथ&lt;/span&gt; हमेशा संबंधित होती है और उसके अनुसार बदलती रहती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;व्याख्या:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;नर और मादा युग्मक अर्थात &lt;strong&gt;शुक्राणु और अंड&amp;nbsp;या अंडाणु क्रमशः एककोशिकीय&lt;/strong&gt; (एककोशिकीय)&lt;strong&gt; &lt;/strong&gt;होते हैं।&lt;/li&gt;
	&lt;li&gt;वे &lt;strong&gt;दोनों&lt;/strong&gt; प्रकृति में &lt;strong&gt;अगुणित (n) &lt;/strong&gt;होते&amp;nbsp;हैं जो द्विगुणित युग्मनज (2n) बनाने के लिए निषेचन से गुजरते हैं।&lt;/li&gt;
	&lt;li&gt;शुक्राणु मानव शरीर की सबसे छोटी कोशिका है।&lt;/li&gt;
	&lt;li&gt;प्रत्येक शुक्राणु एक एकल कोशिका है। शुक्राणु एक नर युग्मक है जो रोगाणु कोशिकाओं से निर्मित होता है।&lt;/li&gt;
	&lt;li&gt;वे &lt;strong&gt;अर्धसूत्रीविभाजन&lt;/strong&gt; द्वारा निर्मित होते हैं, जिसके परिणामस्वरूप अगुणित एककोशिकीय कोशिकाएं होती हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/22/03/F1_Utkarsha_Madhuri_05.03.2022_D1.png&quot; style=&quot; width: 318px; height: 184px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;एक &lt;strong&gt;मादा युग्मक (अंड-n&lt;/strong&gt;) और &lt;strong&gt;एक नर युग्मक (शुक्राणु-n)&lt;/strong&gt; के संलयन द्वारा निषेचन के बाद एक &lt;strong&gt;युग्मनज (2n) &lt;/strong&gt;बनता है। नतीजतन, &lt;strong&gt;युग्मनज बहुकोशिकीय हो&lt;span style=&quot;&quot;&gt;ता&lt;/span&gt;&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;है।&lt;/strong&gt;&lt;br /&gt;
एक भ्रूण बनाने के लिए, &lt;strong&gt;युग्मनज कोशिकाएं गुणित होती हैं और विभाजित (माइटोसिस)&lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;होती हैं&lt;/span&gt;&lt;strong&gt;। भ्रूण एक बहुकोशिकीय संरचना होती&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;है।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Hydrogen.&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Hydrogen is the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;lightest gas&amp;nbsp;&lt;/span&gt;in the world.&lt;/li&gt;
	&lt;li&gt;Hydrogen is a&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;chemical element.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;It is the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;first element&amp;nbsp;&lt;/span&gt;in the&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;periodic table&amp;nbsp;&lt;/span&gt;which is also the lightest.&lt;/li&gt;
	&lt;li&gt;It is found most abundantly in the universe.&lt;/li&gt;
	&lt;li&gt;Most of the mass of the stars and the Sun is made up of hydrogen.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Nitrogen:&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Nitrogen is a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;colorless, odorless,&lt;/span&gt;&amp;nbsp;and&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;tasteless gas.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Its atomic number is&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;7.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Nitrogen gas was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;discovered by Rutherford&amp;nbsp;&lt;/span&gt;in 1773.&lt;/li&gt;
	&lt;li&gt;Nitrogen is the seventh element of the periodic table.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Carbon Dioxide :&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;It is a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;colorless gas with a density of about 53% higher than that of dry air.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Its molecules consist of a carbon atom covalently double bonded to two oxygen atoms.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर है&amp;nbsp;&lt;strong&gt;&lt;u&gt;हाइड्रोजन।&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;हाइड्रोजन दुनिया की &lt;strong&gt;सबसे हल्की गैस&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;हाइड्रोजन एक &lt;strong&gt;रासायनिक तत्व&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;आवर्त सारणी&lt;/strong&gt; का &lt;strong&gt;पहला तत्व&lt;/strong&gt; है जो सबसे हल्का भी है।&lt;/li&gt;
	&lt;li&gt;यह ब्रह्मांड में सर्वाधिक मात्रा में पाया जाता है।&lt;/li&gt;
	&lt;li&gt;तारों और सूर्य का अधिकांश द्रव्यमान हाइड्रोजन से बना है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;नाइट्रोजन:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;नाइट्रोजन एक &lt;strong&gt;रंगहीन, गंधहीन&lt;/strong&gt; और &lt;strong&gt;स्वादहीन गैस&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;इसकी परमाणु संख्या &lt;strong&gt;7&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;रदरफोर्ड &lt;/strong&gt;ने 1773 में नाइट्रोजन गैस की&lt;strong&gt; खोज की थी&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;नाइट्रोजन आवर्त सारणी का सातवाँ तत्व है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;कार्बन डाईऑक्साइड:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह एक &lt;strong&gt;रंगहीन गैस है जिसका घनत्व शुष्क हवा के घनत्व से लगभग 53% अधिक है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इसके अणुओं में एक कार्बन परमाणु होता है जो दो ऑक्सीजन परमाणुओं के सहसंयोजक दोहरे बंध से बना होता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;mitochondria&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The mitochondria are known as the &lt;strong&gt;powerhouses of the cell&lt;/strong&gt; because they generate most of the cell&amp;rsquo;s supply of adenosine triphosphate (ATP), used as a source of chemical energy.&lt;/li&gt;
	&lt;li&gt;In plant cells, mitochondria are the primary site of cellular respiration, where oxygen is used to convert nutrients into energy.&lt;/li&gt;
	&lt;li&gt;During respiration, mitochondria &lt;strong&gt;take in oxygen and release carbon dioxide&lt;/strong&gt; and energy in the form of ATP.&lt;/li&gt;
	&lt;li&gt;They have their own DNA, which is separate from the nuclear DNA, and can replicate independently within the cell.&lt;/li&gt;
	&lt;li&gt;The process of cellular respiration in mitochondria occurs in three main stages: glycolysis, the citric acid cycle, and the electron transport chain.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Peroxisomes&lt;/strong&gt;: Organelles that contain enzymes for oxidative reactions, important in the metabolism of fatty acids and the detoxification of harmful substances.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Chloroplasts&lt;/strong&gt;: Organelles found in plant cells and eukaryotic algae that conduct photosynthesis, where light energy is converted into chemical energy stored in glucose.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Vacuoles&lt;/strong&gt;: Large vesicles in plant cells that store nutrients, waste products, and help maintain turgor pressure against the cell wall.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Electron Transport Chain&lt;/strong&gt;: A series of protein complexes within the inner mitochondrial membrane that transfer electrons from electron donors to electron acceptors via redox reactions, coupled with the transfer of protons (H+ ions) across the membrane.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Adenosine Triphosphate (ATP)&lt;/strong&gt;: The main energy currency of the cell, providing energy for various cellular processes, including muscle contraction, nerve impulse propagation, and chemical synthesis.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;माइटोकॉन्ड्रिया&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;माइटोकॉन्ड्रिया को कोशिका का &lt;strong&gt;शक्तिगृह&lt;/strong&gt; कहा जाता है क्योंकि वे कोशिका के एडेनोसिन ट्राइफॉस्फेट (ATP) की अधिकांश आपूर्ति उत्पन्न करते हैं, जिसका उपयोग रासायनिक ऊर्जा के स्रोत के रूप में किया जाता है।&lt;/li&gt;
	&lt;li&gt;पादप कोशिकाओं में, माइटोकॉन्ड्रिया कोशिकीय श्वसन का प्राथमिक स्थल है, जहाँ ऑक्सीजन का उपयोग पोषक तत्वों को ऊर्जा में बदलने के लिए किया जाता है।&lt;/li&gt;
	&lt;li&gt;श्वसन के दौरान, माइटोकॉन्ड्रिया &lt;strong&gt;ऑक्सीजन ग्रहण करते हैं और कार्बन डाइऑक्साइड&lt;/strong&gt; और ATP के रूप में ऊर्जा मुक्त करते हैं।&lt;/li&gt;
	&lt;li&gt;इनका अपना DNA होता है, जो केन्द्रकीय&amp;nbsp;DNA से अलग होता है, और कोशिका के भीतर स्वतंत्र रूप से प्रतिकृति बना सकते हैं।&lt;/li&gt;
	&lt;li&gt;माइटोकॉन्ड्रिया में कोशिकीय श्वसन की प्रक्रिया तीन मुख्य चरणों में होती है: ग्लाइकोलाइसिस, सिट्रिक अम्ल चक्र और इलेक्ट्रॉन परिवहन शृंखला।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;पेरोक्सिसोम्स&lt;/strong&gt;: ऑर्गेनेल जिसमें ऑक्सीडेटिव प्रतिक्रियाओं के लिए एंजाइम होते हैं, जो वसा अम्लों के उपापचय और हानिकारक पदार्थों के निष्क्रियकरण में महत्वपूर्ण होते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;क्लोरोप्लास्ट&lt;/strong&gt;: पादप कोशिकाओं और यूकेरियोटिक शैवाल में पाए जाने वाले ऑर्गेनेल जो प्रकाश संश्लेषण करते हैं, जहाँ प्रकाश ऊर्जा को ग्लूकोज में संग्रहीत रासायनिक ऊर्जा में परिवर्तित किया जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;रिक्तिकाएँ&lt;/strong&gt;: पादप कोशिकाओं में बड़े पुटिकाएँ जो पोषक तत्वों, अपशिष्ट उत्पादों का भंडारण करती हैं और कोशिका भित्ति के विरुद्ध स्फीति दाब बनाए रखने में मदद करती हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इलेक्ट्रॉन परिवहन शृंखला&lt;/strong&gt;: आंतरिक माइटोकॉन्ड्रियल झिल्ली के भीतर प्रोटीन कॉम्प्लेक्स की एक शृंखला जो इलेक्ट्रॉन दाताओं से इलेक्ट्रॉन ग्राही तक रिडॉक्स अभिक्रियाओं के माध्यम से इलेक्ट्रॉनों को स्थानांतरित करती है, जो झिल्ली के पार प्रोटॉन (H+ आयन) के स्थानांतरण के साथ युग्मित होती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;एडेनोसिन ट्राइफॉस्फेट (ATP)&lt;/strong&gt;: कोशिका की मुख्य ऊर्जा मुद्रा, जो विभिन्न कोशिकीय प्रक्रियाओं, जिसमें पेशी संकुचन, तंत्रिका आवेग प्रसार और रासायनिक संश्लेषण शामिल हैं, के लिए ऊर्जा प्रदान करती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;In the hills the atmospheric pressure is lower than in the plains and therefore water boils at lower temperatures&lt;/strong&gt;&lt;/u&gt;.&lt;br /&gt;
&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The air pressure is comparatively less in high altitudes than at a low altitude.&lt;/li&gt;
	&lt;li&gt;At sea level, the air pressure is the highest.&lt;/li&gt;
	&lt;li&gt;As the altitude increases, the number of air molecules in the air decrease, and with the decrease of air molecules, the pressure also decreases.&lt;/li&gt;
	&lt;li&gt;The pressure of air is due to the movement and collision of the gas particles in the air.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;With an increase in altitude, the number of gas particles decreases, and thus the collision between the gas particles also decreases. So, the pressure also decreases.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Now, with an increase in pressure the boiling temperature of the water also decreases. The water boils at the point where the vapor pressure of the water exceeds the air&amp;nbsp;pressure.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Near the earth&amp;rsquo;s surface, the boiling temperature of the water is 100&amp;deg;C. But&amp;nbsp;as the altitude increases the air pressure decreases and hence the temperature&lt;br /&gt;
	needed to exceed vapor pressure then the air pressure also decreases.&lt;/li&gt;
	&lt;li&gt;So, at a high altitude, the boiling temperature of water decreases.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/07/Reported_2.7.21_Sunny_D1.PNG&quot; style=&quot;width: 382px; height: 383px;&quot; /&gt;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्तर यह है कि &lt;u&gt;&lt;strong&gt;पहाड़ियों में वायुमंडलीय दबाव मैदानों की तुलना में कम होता है और इसलिए पानी कम तापमान पर उबलता है&lt;/strong&gt;&lt;/u&gt; ।&lt;br /&gt;&lt;br /&gt; &lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;प्रमुख बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;ul&gt;&lt;li&gt; अधिक ऊंचाई वाले क्षेत्रों में वायु दाब कम ऊंचाई वाले क्षेत्रों की तुलना में अपेक्षाकृत कम होता है।&lt;/li&gt;&lt;li&gt; समुद्र तल पर वायु दाब सबसे अधिक होता है।&lt;/li&gt;&lt;li&gt; जैसे-जैसे ऊंचाई बढ़ती है, हवा में हवा के अणुओं की संख्या कम होती जाती है, और हवा के अणुओं की संख्या कम होने के साथ-साथ दबाव भी कम होता जाता है।&lt;/li&gt;&lt;li&gt; हवा का दबाव हवा में मौजूद गैस के कणों की गति और उनके आपस में टकराने के कारण होता है।&lt;/li&gt;&lt;li&gt; &lt;strong&gt;ऊंचाई बढ़ने के साथ-साथ गैस के कणों की संख्या कम हो जाती है, और इस प्रकार गैस के कणों के बीच टकराव भी कम हो जाता है। अतः दाब भी कम हो जाता है।&lt;/strong&gt;&lt;/li&gt;&lt;li&gt; &lt;strong&gt;अब, दाब बढ़ने के साथ-साथ पानी का क्वथनांक भी घट जाता है। पानी उस बिंदु पर उबलता है जहाँ पानी का वाष्प दाब वायु दाब से अधिक हो जाता है।&lt;/strong&gt;&lt;/li&gt;&lt;li&gt; पृथ्वी की सतह के निकट, पानी का क्वथनांक 100°C होता है। लेकिन जैसे-जैसे ऊंचाई बढ़ती है, वायु दाब कम होता जाता है और परिणामस्वरूप तापमान भी घटता जाता है।&lt;br /&gt; वाष्प दाब से अधिक होने पर वायु दाब भी कम हो जाता है।&lt;/li&gt;&lt;li&gt; इसलिए, अधिक ऊंचाई पर पानी का क्वथनांक कम हो जाता है। &lt;/li&gt;&lt;/ul&gt;&lt;p&gt;&lt;br /&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/21/07/Reported_2.7.21_Sunny_D1.PNG&quot; style=&quot;width: 382px; height: 383px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is a&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;combination.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;The burning of coal is a &lt;span style=&quot;&quot;&gt;combination&amp;nbsp;&lt;/span&gt;reaction.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;A&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;combination reaction&lt;/span&gt;&amp;nbsp;is a reaction where two or more elements or compounds combine to form a single compound. Such reactions are represented by equations of the following form:&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;X + Y &amp;rarr; XY&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;The combination of two or more elements to form one compound is called a combination reaction.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Other types of Chemical Reactions&lt;/span&gt;:

	&lt;ul&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Decomposition reaction&lt;/span&gt;&lt;/u&gt;:

		&lt;ul&gt;
			&lt;li&gt;The opposite of a combination reaction,&amp;nbsp;a complex molecule breaks down to make simpler ones. Such reactions are represented by equations of the following form:&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;AB &amp;rarr; A + B.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Precipitation reaction&lt;/span&gt;&lt;/u&gt;:&amp;nbsp;
		&lt;ul&gt;
			&lt;li&gt;Two solutions of soluble salts are mixed resulting in an insoluble solid (precipitate) forming.&amp;nbsp;Such reactions are represented by equations of the following form:&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;A + Soluble salt B&amp;nbsp; &amp;rarr; Precipitate + soluble salt C.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Neutralization reaction&lt;/span&gt;&lt;/u&gt;:&amp;nbsp;
		&lt;ul&gt;
			&lt;li&gt;An acid and a base react with each other. Generally, the product of this reaction is salt and water. Such reactions are represented by equations of the following form:&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Acid + Base &amp;rarr; Salt + Water&lt;/span&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Combustion reaction&lt;/span&gt;&lt;/u&gt;:&amp;nbsp;
		&lt;ul&gt;
			&lt;li&gt;Oxygen combines with a compound to form carbon dioxide and water. These reactions are exothermic, meaning they give off heat.&amp;nbsp;Such reactions are represented by equations of the following form:&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;A + O&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;&amp;rarr; H&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;O + CO&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Displacement&amp;nbsp;reaction&lt;/span&gt;&lt;/u&gt;:&amp;nbsp;
		&lt;ul&gt;
			&lt;li&gt;One element takes place with another element in the compound.&amp;nbsp;Such reactions are represented by equations of the following form:&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;A + BC &amp;rarr; AC + B&lt;/span&gt;.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;संयोजन&lt;/span&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 20px;&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कोयले का&amp;nbsp;जलना&amp;nbsp;एक संयुक्त अभिक्रिया है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;एक&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;संयोजन अभिक्रिया&lt;/span&gt;&amp;nbsp;एक &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रिया है जहां दो या दो से अधिक तत्व या यौगिक मिलकर एक एकल यौगिक बनाते हैं। इस तरह की &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रियाओं को निम्नलिखित रूप के समीकरणों द्वारा दर्शाया जाता है:&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;X + Y &amp;rarr; XY.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;दो या दो से अधिक तत्वों के संयोग से एक यौगिक बनता है, संयोजन अभिक्रिया कहलाती है।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 20px;&quot;&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अन्य प्रकार की रासायनिक अभिक्रियाएँ&lt;/span&gt;&amp;nbsp;:

	&lt;ul&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अपघटन अभिक्रिया&lt;/span&gt;&lt;/u&gt;&amp;nbsp;:

		&lt;ul&gt;
			&lt;li&gt;एक संयोजन &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रिया के विपरीत, एक जटिल अणु सरल बनाने के लिए टूट जाता है। ऐसी &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रियाओं को निम्नलिखित रूप के समीकरणों द्वारा दर्शाया जाता है:&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;AB &amp;rarr; A + B.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;strong&gt;शीघ्र​&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;strong&gt;&lt;u&gt; &lt;/u&gt;&lt;/strong&gt;अभिक्रिया&lt;/span&gt;&lt;/u&gt;&amp;nbsp;:
		&lt;ul&gt;
			&lt;li&gt;घुलनशील लवणों के दो विलयन मिश्रित होते हैं जिसके परिणामस्वरूप एक अघुलनशील ठोस (अवक्षेप) बनता है। इस तरह की &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रियाओं को निम्नलिखित रूप के समीकरणों द्वारा दर्शाया जाता है:&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;A + घुलनशील नमक B &amp;rarr; अवक्षेप + घुलनशील नमक C.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदासीनीकरण अभिक्रिया&lt;/span&gt;&lt;/u&gt;&amp;nbsp;:
		&lt;ul&gt;
			&lt;li&gt;एक अम्ल और एक क्षार एक दूसरे के साथ &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रिया करते हैं। आम तौर पर, इस &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रिया का उत्पाद नमक और पानी होता है। इस तरह की &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रियाओं को निम्नलिखित रूप के समीकरणों द्वारा दर्शाया जाता है:&amp;nbsp;&lt;strong&gt;अम्ल​&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;strong&gt; &lt;/strong&gt;+ &lt;/span&gt;&lt;strong&gt;क्षार&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt; &amp;rarr; नमक + पानी.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;दहन अभिक्रिया&lt;/span&gt;&lt;/u&gt;&amp;nbsp;:
		&lt;ul&gt;
			&lt;li&gt;ऑक्सीजन एक यौगिक के साथ मिलकर कार्बन डाइऑक्साइड और पानी बनाती है। ये &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रियाएं एक्ज़ोथिर्मिक हैं, जिसका अर्थ है कि वे गर्मी छोड़ती हैं। ऐसी &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रियाओं को निम्नलिखित रूप के समीकरणों द्वारा दर्शाया जाता है:&amp;nbsp;&lt;span style=&quot;font-weight: 700; &quot;&gt;A + O&lt;/span&gt;&lt;span style=&quot;font-weight: 700;  line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;&amp;rarr; H&lt;/span&gt;&lt;span style=&quot;font-weight: 700;  line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;O + CO&lt;/span&gt;&lt;span style=&quot;font-weight: 700;  line-height: 0; position: relative; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;2.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विस्थापन अभिक्रिया&lt;/span&gt;&lt;/u&gt;&amp;nbsp;:
		&lt;ul&gt;
			&lt;li&gt;यौगिक में एक तत्व दूसरे तत्व के साथ होता है। ऐसी &lt;span style=&quot;&quot;&gt;अभि&lt;/span&gt;क्रियाओं को निम्नलिखित रूप के समीकरणों द्वारा दर्शाया जाता है:&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;A + BC &amp;rarr; AC + B.&lt;/span&gt;&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
